import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/linux-java-version.Bae4eMgj.js";const a=JSON.parse(`{"title":"在 Linux 上安装 Java","description":"手把手指导如何在 Linux 上安装 Java。","frontmatter":{"title":"在 Linux 上安装 Java","description":"手把手指导如何在 Linux 上安装 Java。","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"zh_cn/1.21.10/players/installing-java/linux.md","filePath":"versions/1.21.10/translated/zh_cn/players/installing-java/linux.md","lastUpdated":1766682904000}`);var o={name:`zh_cn/1.21.10/players/installing-java/linux.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">在 Linux 上安装 Java <a class="header-anchor" href="#h1" aria-label="Permalink to “在 Linux 上安装 Java”">​</a></h1><p>这个指南将会指引您在 Linux 上安装 Java 21。</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. 检查 Java 是否已经安装 <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. 检查 Java 是否已经安装”">​</a></h2><p>打开终端输入 <code>java -version</code> 并按下 <code>回车</code>。</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="输入 &quot;java -version&quot; 的终端" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>要使用 Minecraft 1.21，你需要安装至少 Java 21。 如果运行该命令后显示 Java 版本低于 21，你需要更新设备上现有 Java。</p></div><h2 id="2-downloading-and-installing-java" tabindex="-1">2. 下载并安装 Java 21 <a class="header-anchor" href="#2-downloading-and-installing-java" aria-label="Permalink to “2. 下载并安装 Java 21”">​</a></h2><p>我们推荐使用 OpenJDK 21，可以在大多数 Linux 发行版中可用。</p><h3 id="arch-linux" tabindex="-1">Arch Linux <a class="header-anchor" href="#arch-linux" aria-label="Permalink to “Arch Linux”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>更多在 Arch Linux 上安装 Java 的信息可以参考 <a href="https://wiki.archlinuxcn.org/wiki/Java" target="_blank" rel="noreferrer">Arch Linux 中文维基</a>。</p></div><p>您可以从官方仓库安装最新版 JRE：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果您正在运行服务器不需要图形用户界面，您可以安装无头版本：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果您计划开发模组，您需要安装 JDK：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jdk-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="debian-ubuntu" tabindex="-1">Debian/Ubuntu <a class="header-anchor" href="#debian-ubuntu" aria-label="Permalink to “Debian/Ubuntu”">​</a></h3><p>您可以用以下命令使用 <code>apt</code> 安装 Java 21：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openjdk-21-jdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="fedora" tabindex="-1">Fedora <a class="header-anchor" href="#fedora" aria-label="Permalink to “Fedora”">​</a></h3><p>您可以用以下命令使用 <code>dnf</code> 安装 Java 21：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果不需要图形化界面，可以安装 headless 版本：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果您计划开发模组，您需要安装 JDK：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk-devel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="other-linux-distributions" tabindex="-1">其他 Linux 发行版 <a class="header-anchor" href="#other-linux-distributions" aria-label="Permalink to “其他 Linux 发行版”">​</a></h3><p>如果您的发行版未在上文列出，您可以从 <a href="https://adoptium.net/zh-CN/temurin/" target="_blank" rel="noreferrer">Adoptium</a> 下载最新版 JRE。</p><p>如果您计划开发模组，您应该参考您的发行版的替代指南。</p><h2 id="3-verify-that-java-is-installed" tabindex="-1">3. 验证是否已安装 Java 21 <a class="header-anchor" href="#3-verify-that-java-is-installed" aria-label="Permalink to “3. 验证是否已安装 Java 21”">​</a></h2><p>安装完成后，您可以打开终端并输入 <code>java -version</code> 来验证 Java 21 是否已安装。</p><p>如果命令成功执行，你可以看到类似前文所示的内容，Java 版本被显示出来：</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="输入 &quot;java -version&quot; 的终端" loading="lazy"></p>`,33)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};